settings.custom_css:
@media only screen and (max-width: 1450px) and (min-width: 1200px) {
    selector .elementor-heading-title {
        font-size: 5.4rem;
    }
}

selector a:hover{
    color: #80BBBC !important;
}

selector .elementor-post__read-more:hover{
    color: #80BBBC !important;
}

selector a, selector .elementor-post__read-more{
    transition: .2s;
}

